import numpy as np
import random

# --- Problem Data ---

# Resource usage per product
tech_prep = {'A': 1, 'B': 2, 'C': 1}
labor     = {'A':10, 'B': 4, 'C': 5}
material  = {'A': 3, 'B': 2, 'C': 1}

limits = {'tech_prep':100, 'labor':700, 'material':400}

# Profit tiers: (lower, upper, profit)
# For each product, define tuples of (lower, upper, profit)
profit_tiers = {
    'A': [
        (0, 40, 10),
        (41, 100, 9),
        (101,150,8),
        (151,9999,7)   # arbitrarily large upper
    ],
    'B': [
        (0, 50, 6),
        (51,100,4),
        (101,9999,3)
    ],
    'C': [
        (0,100,5),
        (101,9999,4)
    ]
}
# For tier membership constraints (for repair)
tier_bounds = {
    'A': [(0,40),(41,100),(101,150),(151,9999)],
    'B': [(0,50),(51,100),(101,9999)],
    'C': [(0,100),(101,9999)]
}

# Variable bounds
var_bounds = {'A': (0, 9999), 'B': (0, 9999), 'C': (0, 9999)}

# --- Solution representation ---
# A solution is a dict: {'A': int, 'B': int, 'C': int}

# --- Objective and constraints evaluation ---

def get_profit_and_tiers(sol):
    """
    Returns (profit, tier_ids), where tier_ids = {'A':i, ...}
    """
    profit = 0
    tiers = {}
    for prod in ['A','B','C']:
        x = sol[prod]
        for i,(lo,hi,p) in enumerate(profit_tiers[prod]):
            if lo <= x <= hi:
                profit += x * p
                tiers[prod] = i
                break
        else:
            # Above all tiers, take last tier
            i = len(profit_tiers[prod])-1
            profit += x * profit_tiers[prod][i][2]
            tiers[prod] = i
    return profit, tiers

def get_resource_usage(sol):
    return {
        'tech_prep': tech_prep['A']*sol['A'] + tech_prep['B']*sol['B'] + tech_prep['C']*sol['C'],
        'labor'    : labor['A']*sol['A'] + labor['B']*sol['B'] + labor['C']*sol['C'],
        'material' : material['A']*sol['A'] + material['B']*sol['B'] + material['C']*sol['C']
    }

def is_feasible(sol):
    usage = get_resource_usage(sol)
    for r in ['tech_prep','labor','material']:
        if usage[r] > limits[r]:
            return False
    # Tier membership
    for prod in ['A','B','C']:
        x = sol[prod]
        tb = tier_bounds[prod]
        found = False
        for (lo,hi) in tb:
            if lo <= x <= hi:
                found = True
                break
        if not found:
            return False
    return True

def penalty(sol, penalty_weight=1e5):
    """
    Compute penalty for constraint violations.
    """
    usage = get_resource_usage(sol)
    pen = 0
    for r in ['tech_prep','labor','material']:
        excess = usage[r] - limits[r]
        if excess > 0:
            pen += penalty_weight * excess
    # Tier membership: penalize if not in any tier
    for prod in ['A','B','C']:
        x = sol[prod]
        tb = tier_bounds[prod]
        in_any = any(lo <= x <= hi for (lo,hi) in tb)
        if not in_any:
            pen += penalty_weight * (abs(x))  # force reduction
    return pen

def objective(sol):
    profit, _ = get_profit_and_tiers(sol)
    pen = penalty(sol)
    return profit - pen

# --- Low-level heuristics (operators) ---

def greedy_construction(_):
    """
    Build a feasible solution greedily: fill products in order of profit/resource ratio.
    """
    sol = {'A':0,'B':0,'C':0}
    # For each product, find best tier's per-unit profit
    ratios = []
    for prod in ['A','B','C']:
        max_pu_profit = max([tier[2] for tier in profit_tiers[prod]])
        res = tech_prep[prod] + labor[prod]/limits['labor']*limits['tech_prep'] + material[prod]/limits['material']*limits['tech_prep']
        ratios.append((max_pu_profit/res,prod))
    ratios.sort(reverse=True)
    # Try to fill in sorted order
    remain = get_resource_usage(sol)
    remain = {k: limits[k] - remain[k] for k in remain}
    for _,prod in ratios:
        for tier in profit_tiers[prod]:
            lo,hi,_ = tier
            # Try to fill up to hi
            for x in range(hi,lo-1,-1):
                test_sol = sol.copy()
                test_sol[prod] = x
                ru = get_resource_usage(test_sol)
                if all(ru[r]<=limits[r] for r in ru):
                    sol[prod] = x
                    remain = {k: limits[k]-ru[k] for k in ru}
                    break
            # Only fill one tier per product
            if sol[prod]>0:
                break
    return sol

def local_search_swap(sol):
    """
    Try to increment or decrement one product and adjust another to maintain feasibility.
    """
    s = sol.copy()
    prods = ['A','B','C']
    inc = random.choice([1,-1])
    i = random.choice(prods)
    # Move in random direction
    s[i] = max(0, s[i]+inc)
    # Repair if infeasible
    s = repair_tier(s)
    if not is_feasible(s):
        # Try to decrement another variable to compensate
        j = random.choice([p for p in prods if p!=i])
        if inc==1 and s[j]>0:
            s[j] = max(0, s[j]-1)
        elif inc==-1:
            s[j] = s[j]+1
        s = repair_tier(s)
    return s

def random_perturbation(sol):
    """
    Randomly perturb the solution within tier bounds, then repair.
    """
    s = sol.copy()
    for prod in ['A','B','C']:
        lo,hi = get_tier_bounds(prod, s[prod])
        if lo==hi:
            continue
        # Move randomly within tier
        delta = random.randint(-2,2)
        s[prod] = min(max(s[prod]+delta,lo),hi)
    s = repair_tier(s)
    return s

def crossover_repair(sol):
    """
    Generate a new solution by mixing variables from best-known solutions and repair.
    """
    # Take two random solutions from history if available, else random perturbation
    if len(history_best)>1:
        p1, p2 = random.sample(history_best,2)
        s = {}
        for prod in ['A','B','C']:
            s[prod] = random.choice([p1[prod],p2[prod]])
    else:
        s = sol.copy()
    s = repair_tier(s)
    return s

def repair_tier(sol):
    """
    For each variable, if not in a tier, project to nearest valid tier.
    """
    s = sol.copy()
    for prod in ['A','B','C']:
        x = s[prod]
        tb = tier_bounds[prod]
        min_dist = float('inf')
        nearest = x
        for lo,hi in tb:
            if lo <= x <= hi:
                nearest = x
                break
            # Find nearest bound
            if x < lo:
                if lo - x < min_dist:
                    min_dist = lo-x
                    nearest = lo
            elif x > hi:
                if x - hi < min_dist:
                    min_dist = x-hi
                    nearest = hi
        s[prod] = nearest
    # Project to integer
    for prod in s:
        s[prod] = int(round(s[prod]))
    return s

def get_tier_bounds(prod, x):
    """
    Return (lo,hi) for tier corresponding to x
    """
    for lo,hi in tier_bounds[prod]:
        if lo <= x <= hi:
            return (lo,hi)
    # If not, return nearest tier
    tb = tier_bounds[prod]
    if x < tb[0][0]:
        return tb[0]
    if x > tb[-1][1]:
        return tb[-1]
    # Otherwise, find nearest
    for lo,hi in tb:
        if x<lo:
            return (lo,hi)
    return (tb[0][0], tb[0][1])

# --- Hyper-heuristic selection (Reinforcement-learning style) ---

# List of operators
operators = [
    greedy_construction,
    local_search_swap,
    random_perturbation,
    crossover_repair
]
op_names = [
    "greedy_construction",
    "local_search_swap",
    "random_perturbation",
    "crossover_repair"
]

op_count = len(operators)
op_scores = [1.0 for _ in range(op_count)] # start neutral
op_uses   = [1 for _ in range(op_count)]

# Operator selection parameters
explore_prob = 0.1  # probability to choose a random operator

def select_operator():
    if random.random() < explore_prob:
        return random.randint(0,op_count-1)
    # Softmax selection
    exp_scores = np.exp(op_scores/np.max(op_scores))
    probs = exp_scores/np.sum(exp_scores)
    return np.random.choice(op_count,p=probs)

def update_operator_score(op_idx, reward):
    alpha = 0.3
    op_scores[op_idx] = (1-alpha)*op_scores[op_idx] + alpha*reward
    op_uses[op_idx] += 1

# --- Main Loop ---

MAX_ITERS = 2000

# Keep history for crossover and final best
history_best = []

# Start with greedy construction
current_sol = greedy_construction(None)
current_obj = objective(current_sol)
best_sol = current_sol.copy()
best_obj = current_obj

history_best.append(best_sol.copy())

for it in range(MAX_ITERS):
    op_idx = select_operator()
    op = operators[op_idx]

    # Apply operator
    new_sol = op(current_sol)

    # Feasibility repair
    new_sol = repair_tier(new_sol)
    # If over resource, project down
    for _ in range(3):
        usage = get_resource_usage(new_sol)
        over = [r for r in ['tech_prep','labor','material'] if usage[r]>limits[r]]
        if not over:
            break
        # Reduce most-overused resource
        for r in over:
            dec_order = sorted(['A','B','C'], key=lambda p: get_resource_usage(new_sol)[r], reverse=True)
            for p in dec_order:
                if new_sol[p]>0:
                    new_sol[p] -= 1
                    new_sol = repair_tier(new_sol)
                    break

    new_obj = objective(new_sol)
    reward = 0
    if new_obj > current_obj:
        reward = 1
        current_sol = new_sol
        current_obj = new_obj
        if new_obj > best_obj:
            best_sol = new_sol.copy()
            best_obj = new_obj
            history_best.append(best_sol.copy())
    else:
        reward = -0.5
        # Accept with small probability for diversification
        if random.random()<0.01:
            current_sol = new_sol
            current_obj = new_obj

    update_operator_score(op_idx, reward)

    # Occasionally add best to history, keep short history
    if it%200==0 and best_sol not in history_best:
        history_best.append(best_sol.copy())
    history_best = history_best[-5:]

# --- Print best solution ---
final_profit, tiers = get_profit_and_tiers(best_sol)
print(f"OBJECTIVE_VALUE: {final_profit}")
